import json, re
d=json.load(open('outputs/gate_e2e_final2/workforce/drb_72_ai_labor/verification_details.json'))

# classifier heuristic: insight/synthesis markers vs atomic-number facts
INSIGHT_MARK = re.compile(r'\b(suggest|imply|indicate|however|whereas|while|although|despite|thus|therefore|consistent with|by contrast|reflect|underscore|highlight|reinforc|because|driven by|as a result|point to|paradox|tension|nuanc|trade-?off|combined with|taken together|across studies|converge|diverge|consensus|conflict|caution|not equate|rather than|shift|transform|emerge)\b', re.I)
NUM = re.compile(r'\d')
PCT = re.compile(r'\d+(\.\d+)?\s?%|\bpercent')

def classify(s):
    has_insight = bool(INSIGHT_MARK.search(s))
    # strip citation tokens for number check
    core = re.sub(r'\[#ev:[^\]]+\]','',s)
    has_num = bool(NUM.search(core))
    if has_insight and not PCT.search(core):
        return 'SYNTH/INSIGHT'
    if has_insight:
        return 'SYNTH+NUM'
    if has_num:
        return 'ATOMIC-NUM'
    return 'QUAL-FACT'

drop_by_class={}; keep_by_class={}
drop_ex={}; keep_ex={}
for sec in d['sections']:
    for item in sec['dropped']:
        s=item['sentence']; c=classify(s)
        drop_by_class[c]=drop_by_class.get(c,0)+1
        drop_ex.setdefault(c,[]).append((s, item.get('failure_reasons')))
    for item in sec['kept']:
        s = item['sentence'] if isinstance(item,dict) else item
        c=classify(s)
        keep_by_class[c]=keep_by_class.get(c,0)+1
        keep_ex.setdefault(c,[]).append(s)

print("=== DROPPED by class ==="); 
for k,v in sorted(drop_by_class.items(),key=lambda x:-x[1]): print(f"  {k}: {v}")
print("=== KEPT by class ===")
for k,v in sorted(keep_by_class.items(),key=lambda x:-x[1]): print(f"  {k}: {v}")
print("\nTotal dropped:",sum(drop_by_class.values()),"Total kept:",sum(keep_by_class.values()))
EOF

